// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";

/// @title Payment Contract
/// @notice Handles creation, tracking, and email status of payments
contract Payment is Ownable {

    /// @notice Constructor sets the deployer as the contract owner
    constructor() Ownable(msg.sender) {}  // Pass deployer as owner

    /// @notice Structure to store all relevant details for a payment
    struct PaymentRecord {
        string quote_request_id;       // ID of the quote request associated with payment
        string transaction_id;         // Unique payment transaction ID
        string payment_type;           // Payment type (e.g., "ETH")
        uint256 amount;                // Total payment amount
        string amount_purpose;         // Purpose of the amount (e.g., "initial_deposit", "balance")
        uint256 blockchain_gas_amount; // Gas amount paid for blockchain transaction
        string source_wallet;          // Source wallet (e.g., "MetaMask")
        string status;                 // Payment status (e.g., "pending", "completed", "failed")
        uint256 created_at;            // Timestamp of payment creation
        string created_by;             // Creator of the payment record
        bool payment_email_sent;       // Flag to track if confirmation email was sent
        string user_id;                // Associated user ID
        string transaction_hash;       // Blockchain transaction hash (optional)
        uint256 confirmed_at;          // Timestamp when payment is confirmed (optional)
    }

    /// @notice Mapping to store PaymentRecord by transaction_id
    mapping(string => PaymentRecord) private payments;

    /// @notice Event emitted when a new payment is created
    event PaymentCreated(string indexed transaction_id, uint256 amount, string status);

    /// @notice Event emitted when payment email is marked as sent
    event EmailMarkedSent(string indexed transaction_id);

    /// @notice Create a new payment record
    /// @param _payment The PaymentRecord object containing payment details
    /// @dev Only callable by the contract owner
    function createPayment(PaymentRecord memory _payment) external onlyOwner {
        require(bytes(_payment.transaction_id).length > 0, "Transaction ID required");
        require(_payment.amount > 0, "Amount must be greater than zero");
        require(bytes(_payment.payment_type).length > 0, "Payment type required");

        PaymentRecord storage p = payments[_payment.transaction_id];

        // Copy fields from input PaymentRecord
        p.quote_request_id = _payment.quote_request_id;
        p.transaction_id = _payment.transaction_id;
        p.payment_type = _payment.payment_type;
        p.amount = _payment.amount;
        p.amount_purpose = _payment.amount_purpose;
        p.blockchain_gas_amount = _payment.blockchain_gas_amount;
        p.source_wallet = _payment.source_wallet;
        p.status = _payment.status;
        p.created_at = block.timestamp;
        p.created_by = _payment.created_by;
        p.payment_email_sent = false;  // Initialize email flag as false
        p.user_id = _payment.user_id;
        p.transaction_hash = _payment.transaction_hash;
        p.confirmed_at = _payment.confirmed_at;

        emit PaymentCreated(_payment.transaction_id, _payment.amount, _payment.status);
    }

    /// @notice Retrieve a payment record by transaction_id
    /// @param _transaction_id Unique transaction ID of the payment
    /// @return PaymentRecord associated with the transaction_id
    /// @dev Reverts if payment does not exist
    function getPayment(string memory _transaction_id) external view returns (PaymentRecord memory) {
        PaymentRecord memory p = payments[_transaction_id];
        require(bytes(p.transaction_id).length > 0, "Payment does not exist");
        return p;
    }

    /// @notice Mark that a payment confirmation email has been sent
    /// @param _transaction_id Unique transaction ID of the payment
    /// @dev Only callable by the contract owner
    function markEmailSent(string memory _transaction_id) external onlyOwner {
        PaymentRecord storage p = payments[_transaction_id];
        require(bytes(p.transaction_id).length > 0, "Payment does not exist");
        p.payment_email_sent = true;

        emit EmailMarkedSent(_transaction_id);
    }

    /// @notice Check if a payment exists for a given transaction_id
    /// @param _transaction_id Unique transaction ID
    /// @return True if payment exists, false otherwise
    function paymentExists(string memory _transaction_id) external view returns (bool) {
        return bytes(payments[_transaction_id].transaction_id).length > 0;
    }
}

